import React from 'react';
import { Routes, Route, Link, useLocation } from 'react-router-dom';
import Home from './components/Home';
import Login from './components/Login';
import Register from './components/Register';
import Dashboard from './components/Dashboard';
import DoctorDashboard from './components/DoctorDashboard';

function App() {
  const location = useLocation();
  
  // Hide header on dashboard pages (keeps homepage hero clean)
  const hideHeader = location.pathname === '/dashboard' || location.pathname === '/doctor-dashboard';

  return (
    <div className="app">
      {!hideHeader && (
        <header className="site-header">
          <div className="header-inner">
            <Link to="/" className="brand">
              <img src="/logo.svg" alt="VitalLink" className="logo" />
            </Link>

            <nav className="main-nav">
              <Link to="/">Home</Link>
              <Link to="/login" className="nav-cta">Sign in</Link>
              <Link to="/register" className="nav-cta btn-outline">Sign up</Link>
            </nav>
          </div>
        </header>
      )}

      <main>
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/login" element={<Login />} />
          <Route path="/register" element={<Register />} />
          <Route path="/dashboard" element={<Dashboard />} />
          <Route path="/doctor-dashboard" element={<DoctorDashboard />} />
        </Routes>
      </main>
    </div>
  );
}

export default App;
